ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name WHERE {
  ?c a :Courses .
  ?r a :Software .
  ?c p:hasSoftware ?r .
  ?r p:name ?name .
  ?c p:course_name ?course_name_f .
  FILTER(STR(?course_name_f) = "Introductory Organic Chemistry")
} }
  component_2: { SELECT ?title WHERE {
  ?c a :Courses .
  ?r a :Textbooks .
  ?c p:hasTextbooks ?r .
  ?r p:title ?title .
  ?c p:course_name ?course_name_f .
  FILTER(STR(?course_name_f) = "Introductory Organic Chemistry")
} }
  full: { SELECT ?title ?name WHERE {
  ?c a :Courses .
  ?r a :Textbooks .
  ?c p:hasTextbooks ?r .
  ?sw a :Software .
  ?c p:hasSoftware ?sw .
  ?r p:title ?title .
  ?sw p:name ?name .
  ?c p:course_name ?course_name_f .
  FILTER(STR(?course_name_f) = "Introductory Organic Chemistry")
} }
}
